const raw = $json.output;
const jsonMatch = typeof raw === 'string' ? raw.match(/\{[\s\S]*\}/) : null;
const data = jsonMatch ? JSON.parse(jsonMatch[0]) : raw;

let segments = [];

// 1. Vehicle category (SUVs, vans, motorcycles, etc.)
if (data.category) {
  segments.push(data.category.toLowerCase().replace(/\s+/g, '-'));
}

// 2. Brand (toyota, honda, etc.)
if (data.brand) {
  segments.push(data.brand.toLowerCase().replace(/\s+/g, '-'));
}

// 3. Model (prado, axio, etc.)
if (data.model) {
  segments.push(data.model.toLowerCase().replace(/\s+/g, '-'));
}

// 4. Location
if (data.location) {
  segments.push(data.location.toLowerCase().replace(/\s+/g, '-'));
}

// 5. Year range (e.g. 2016-2020)
if (data.year_min || data.year_max) {
  const yMin = data.year_min || 2000;
  const yMax = data.year_max || new Date().getFullYear();
  segments.push(`${yMin}-${yMax}`);
}

// 6. Fuel type (diesel, petrol, hybrid, electric)
if (data.fuel_type) {
  segments.push(data.fuel_type.toLowerCase());
}

// 7. Price range
const minPrice = data.min_price || 0;
const maxPrice = data.max_price || 200000000;
segments.push(`price-${minPrice}-${maxPrice}`);

// 8. Mileage
if (data.max_mileage) {
  segments.push(`mileage-0-${data.max_mileage}`);
}

if (data.condition && 
    data.condition !== null && 
    data.condition !== '' &&
    data.condition !== 'null' &&
    data.condition !== 'undefined') {
  const condition = data.condition.toLowerCase().trim();
  if (condition === 'unregistered' || condition === 'brand-new' || condition === 'new') {
    segments.push('unregistered');
  } else if (condition === 'registered' || condition === 'used') {
    segments.push('registered');
  }
}
const url = "https://riyasewana.com/search/" + segments.join('/');

return { url: url };

const raw = $json.output;
const jsonMatch = typeof raw === 'string' ? raw.match(/\{[\s\S]*\}/) : null;
const data = jsonMatch ? JSON.parse(jsonMatch[0]) : raw;

const categoryMap = {
  'car': 'cars', 'cars': 'cars',
  'suv': 'cars', 'suvs': 'cars',
  'van': 'vans', 'vans': 'vans',
  'motorcycle': 'motorbikes', 'motorbikes': 'motorbikes',
  'truck': 'trucks', 'lorry': 'trucks',
  'bus': 'buses'
};

const cat = data.category ? (categoryMap[data.category.toLowerCase()] || 'cars') : 'cars';
let url = `https://ikman.lk/en/ads/sri-lanka/${cat}`;

if (data.brand) {
  url += "/" + data.brand.toLowerCase().replace(/\s+/g, '-');
}
if (data.model) {
  url += "/" + data.model.toLowerCase().replace(/\s+/g, '-');
}

const params = [];
if (data.min_price) params.push(`price_min=${data.min_price}`);
if (data.max_price) params.push(`price_max=${data.max_price}`);
if (data.max_mileage) params.push(`mileage_max=${data.max_mileage}`);
if (data.fuel_type) params.push(`fuel_type=${data.fuel_type.toLowerCase()}`);
if (data.condition) {
  const c = data.condition.toLowerCase();
  if (c.includes('new') || c.includes('unregistered')) params.push('condition=brand-new');
  else if (c.includes('used') || c.includes('registered')) params.push('condition=used');
}

params.push('sort_by=relevance');
url += "?" + params.join("&");

return { url: url };

const items = $input.all();
const riya = items[0].json;
const ikman = items[1] ? items[1].json : null;

// Riyasewana listings
const riyaTitles = Array.isArray(riya.title) ? riya.title : [];
const riyaLinks = Array.isArray(riya.Link) ? riya.Link : [];
const riyaPrices = Array.isArray(riya.Price) ? riya.Price : [];

const riyaText = riyaTitles.length > 0
  ? riyaTitles.slice(0,5).map((item, i) => {
      const name = typeof item === 'object' ? item.title : item;
      const link = typeof item === 'object' ? item.href : (riyaLinks[i] || "");
      const price = String(riyaPrices[i] || "Price not listed");
      return `${i+1}. ${name}\n💰 ${price}\n🔗 ${link}`;
    }).join("\n\n")
  : "No results found on Riyasewana";

// ikman listings
let ikmanText = "No results found on ikman";
if (ikman) {
  const ikmanTitles = Array.isArray(ikman.title) ? ikman.title : [];
  const ikmanLinks = Array.isArray(ikman.Link) ? ikman.Link : [];
  const ikmanPrices = Array.isArray(ikman.Price) ? ikman.Price : [];

  const seen = new Set();
  const filtered = [];

  for (let i = 0; i < ikmanTitles.length; i++) {
    const item = ikmanTitles[i];
    const name = typeof item === 'object' ? item.title : item;
    let link = ikmanLinks[i] || "";
    if (typeof link === 'object') link = link.href || "";

    if (link.includes('/boost-ad')) continue;
    if (!link) continue;
    if (!link.startsWith('http')) link = 'https://ikman.lk' + link;
    if (seen.has(link)) continue;
    seen.add(link);

    const price = String(ikmanPrices[i] || "Price not listed");
    filtered.push({ name, link, price });
  }

  if (filtered.length > 0) {
    ikmanText = filtered.slice(0,5).map((item, i) =>
      `${i+1}. ${item.name}\n💰 ${item.price}\n🔗 ${item.link}`
    ).join("\n\n");
  }
}

return {
  message: `🚗 Results from Riyasewana:\n\n${riyaText}\n\n━━━━━━━━━━━━━━━\n\n🏪 Results from ikman:\n\n${ikmanText}`,
  hasResults: riyaTitles.length > 0 || (ikman && Array.isArray(ikman.title) && ikman.title.length > 0)
};
